What does this program print?

```cpp
#include <iostream>
#include <memory>

struct T {
    int v;
    T(int x) : v(x) { std::cout << "made " << v << "\n"; }
    ~T() { std::cout << "gone " << v << "\n"; }
};

int main() {
    auto p = std::make_unique<T>(3);
    p.reset();
    std::cout << "end\n";
    return 0;
}
```

